        }
      }
      default:
        return jsonResponse({ error: `Unknown task: ${task}` }, 400);
    }
  } catch (err: unknown) {
    const message = toErrorMessage(err);
    console.error(`[ai-prompt] Error handling task ${task}:`, message);
