export interface EdgeBootstrapOptions {
  functionName: string;
  logPrefix: string;
  method?: string;
  parseBody?: BodyParseMode;
  corsPreflight?: boolean;
  errorResponseFormat?: ErrorResponseFormat;
  invalidJsonMessage?: string;
  invalidJsonShapeMessage?: string;
